import React from 'react';

const categories = [
  'All Projects',
  'Selected Work',
  'Narrative',
  'Music Videos',
  'Commercials',
];

const roles = ['DIRECTOR', 'EDITOR'];

interface HeaderProps {
  selectedCategory: string;
  onSelectCategory: (cat: string) => void;
  selectedRole: string | null;
  onSelectRole: (role: string | null) => void;
}

const Header: React.FC<HeaderProps> = ({ selectedCategory, onSelectCategory, selectedRole, onSelectRole }) => {
  return (
    <header className="flex justify-between px-8 py-6 text-white">
      <div className="text-left space-y-1 text-xs uppercase tracking-wide">
        <p className="font-mono">Archive</p>
        {categories.map((cat, i) => (
          <p
            key={i}
            className={`cursor-pointer hover:opacity-60 ${selectedCategory === cat ? 'font-bold' : ''}`}
            onClick={() => onSelectCategory(cat)}
          >
            {cat}
          </p>
        ))}
      </div>

      <div className="text-center">
        <h1 className="text-4xl font-serif">MIGUEL HILARIO VERDUZCO</h1>

        {/* Centered, typographic role toggle where + = all */}
        <div className="role-toggle mt-2 flex justify-center items-center text-xs uppercase font-mono tracking-widest">
          <span
            role="button"
            tabIndex={0}
            onClick={() => onSelectRole(selectedRole === 'DIRECTOR' ? null : 'DIRECTOR')}
            onKeyDown={(e) => { if (e.key === 'Enter' || e.key === ' ') onSelectRole(selectedRole === 'DIRECTOR' ? null : 'DIRECTOR'); }}
            className={`mx-2 select-none transition-opacity ${selectedRole === 'DIRECTOR' ? 'role-active' : ''}`}
            aria-pressed={selectedRole === 'DIRECTOR'}
          >
            DIRECTOR
          </span>

          <span
            role="button"
            tabIndex={0}
            onClick={() => onSelectRole(null)}
            onKeyDown={(e) => { if (e.key === 'Enter' || e.key === ' ') onSelectRole(null); }}
            className={`mx-2 select-none transition-opacity plus ${selectedRole === null ? 'all-active' : ''}`}
            aria-pressed={selectedRole === null}
            aria-label="Show all roles"
          >
            +
          </span>

          <span
            role="button"
            tabIndex={0}
            onClick={() => onSelectRole(selectedRole === 'EDITOR' ? null : 'EDITOR')}
            onKeyDown={(e) => { if (e.key === 'Enter' || e.key === ' ') onSelectRole(selectedRole === 'EDITOR' ? null : 'EDITOR'); }}
            className={`mx-2 select-none transition-opacity ${selectedRole === 'EDITOR' ? 'role-active' : ''}`}
            aria-pressed={selectedRole === 'EDITOR'}
          >
            EDITOR
          </span>
        </div>
      </div>

      <div className="text-right text-xs uppercase font-mono">
        <p className="cursor-pointer hover:opacity-60">Information</p>
      </div>
    </header>
  );
};

export default Header;
